import { classNames } from ':helpers/classnames';
import { type RefObject, useState } from 'react';

import { countOfOverflowNodes, throttle } from '../helper';
import { useResizeObserver } from './useResizeObserver';

const MAX_OVERFLOW_VALUES_COUNT = 99;

interface OverflowTextProps {
	hiddenRef: RefObject<HTMLParagraphElement>;
	inputRef: RefObject<HTMLInputElement | HTMLButtonElement | HTMLDivElement>;
}

interface OverflowText {
	count: number;
	className: string;
}

const calcPadding = (el: CSSStyleDeclaration, padding: 'left' | 'right'): number =>
	+el.getPropertyValue(`padding-${padding}`).slice(0, -2);

export const useOverflowText = ({ hiddenRef, inputRef }: OverflowTextProps): OverflowText => {
	const [count, setCount] = useState(0);
	const isHasHiddenValues = count > 0;

	const onResize = throttle((target: HTMLInputElement) => {
		if (!hiddenRef.current) {
			return;
		}

		const { clientWidth } = target;
		const el = globalThis.getComputedStyle(target, null);
		const pr = calcPadding(el, 'right');
		const pl = calcPadding(el, 'left');
		hiddenRef.current.style.width = `${clientWidth - pl - pr}px`;

		const { right } = hiddenRef.current.getBoundingClientRect();
		const cnt = countOfOverflowNodes({
			parentRight: right,
			nodes: hiddenRef.current.childNodes,
		});

		const newCount = Math.min(MAX_OVERFLOW_VALUES_COUNT, cnt);
		// Обновляем count только если значение действительно изменилось
		// это поможет избежать лишних ререндеров
		setCount(prevCount => (prevCount !== newCount ? newCount : prevCount));
	}, 200);

	useResizeObserver(inputRef, onResize);
	const className = classNames('dsb__overflow__count', isHasHiddenValues ? 'show-count' : '', 'center-counter');

	return { count, className };
};
